/**
 * Rust Bindings Adapter — connects TypeScript to the Rust core via NAPI-RS.
 * 
 * This adapter loads the native module generated by napi-rs and delegates
 * all agent operations to the Rust core.
 * 
 * Falls back to a mock mode if the native module is not available
 * (e.g., during development or when the Rust build hasn't been run).
 */

import type { AgentEnginePort, StreamChunk, SessionStats, AgentState } from '../../domain/ports/agent-engine.js';

/** Native module interface — matches the NAPI exports from lib.rs */
interface NativeTsAgent {
  new (name: string, description: string, prompt: string): NativeTsAgent;
  run(prompt: string): Promise<string>;
  getState(): Promise<string>;
  getStats(): Promise<string>;
  setBudget(maxTokens: number, budgetUsd: number): Promise<void>;
}

interface NativeModule {
  TsAgent: NativeTsAgent;
}

export class RustBindingsAdapter implements AgentEnginePort {
  private agent: NativeTsAgent | null = null;
  private agentId: string = '';
  private useMock: boolean = false;

  /**
   * Load the native NAPI module.
   * Tries multiple paths for cross-platform compatibility.
   */
  private loadNative(): NativeModule | null {
    const candidates = [
      // NAPI-RS release build
      '../../core/target/release/imzx_core.linux-arm64-gnu.node',
      '../../core/target/release/imzx_core.android-arm64.node',
      '../../core/target/release/libimzx_core.so',
      // Debug build
      '../../core/target/debug/imzx_core.linux-arm64-gnu.node',
      '../../core/target/debug/imzx_core.android-arm64.node',
    ];

    for (const candidate of candidates) {
      try {
        // Use createRequire for native modules in ESM context
        const { createRequire } = await import('node:module');
        const require = createRequire(import.meta.url);
        return require(candidate) as NativeModule;
      } catch {
        // Try next candidate
      }
    }

    return null;
  }

  async initialize(id: string, description: string, prompt: string): Promise<string> {
    this.agentId = id;

    if (!this.agent) {
      try {
        const native = this.loadNative();
        if (native) {
          this.agent = new native.TsAgent(id, description, prompt);
          return `[NAPI-RS] Agent '${id}' initialized with Rust core`;
        }
      } catch (err) {
        console.warn('[WARN] Native module not available, using mock mode');
      }

      // Fallback: mock mode
      this.useMock = true;
      return `[Mock] Agent '${id}' initialized (native module not built)`;
    }

    return `[Re-initialized] Agent '${id}'`;
  }

  async run(prompt: string): Promise<string> {
    if (this.useMock) {
      return this.mockRun(prompt);
    }

    if (!this.agent) {
      throw new Error('Agent not initialized. Call initialize() first.');
    }

    return this.agent.run(prompt);
  }

  async getState(): Promise<AgentState> {
    if (this.useMock) return 'idle';
    if (!this.agent) throw new Error('Agent not initialized');
    const state = await this.agent.getState();
    return state.toLowerCase() as AgentState;
  }

  async getStats(): Promise<SessionStats> {
    if (this.useMock) {
      return { totalInputTokens: 0, totalOutputTokens: 0, totalCostUsd: 0, requestCount: 0 };
    }
    if (!this.agent) throw new Error('Agent not initialized');
    const raw = await this.agent.getStats();
    const parsed = JSON.parse(raw);
    return {
      totalInputTokens: parsed.total_input_tokens,
      totalOutputTokens: parsed.total_output_tokens,
      totalCostUsd: parsed.total_cost_usd,
      requestCount: parsed.request_count,
    };
  }

  async setBudget(maxTokens: number, budgetUsd: number): Promise<void> {
    if (this.useMock) return;
    if (!this.agent) throw new Error('Agent not initialized');
    await this.agent.setBudget(maxTokens, budgetUsd);
  }

  /** Mock run for development without native module. */
  private mockRun(prompt: string): string {
    return JSON.stringify({
      agent: this.agentId,
      input: prompt,
      response: `[Mock] Agent processed: "${prompt.substring(0, 100)}..."`,
      tokens: { input: Math.floor(prompt.length / 4), output: 50 },
    });
  }
}
